Persist -> { String:query }
Commit -> {}
Rollback -> {}

Transaction -> {
  String:name
  Persist -< e {
    -> db.execute{query -> e.query}!
  }
  Commit -< e {
    -> db.commit{}!
  }
  Rollback -< e {
    -> db.rollback{}!
  }
  save -> {
    String:query
    >- Persist{query -> query}
  }
  finish -> {
    >- Commit{}
  }
}
